// TODO: This was a spike, clean up later
// Quick test of Redis integration
const redis = require('redis');
const client = redis.createClient(); // hardcoded localhost

async function cacheUser(user) {
  // no error handling, no TTL, no serialization check
  await client.set(`user:${user.id}`, JSON.stringify(user));
}

async function getUser(id) {
  const data = await client.get(`user:${id}`);
  return JSON.parse(data); // crashes on null
}

module.exports = { cacheUser, getUser };
